import axios from 'axios';
import { useUserPreferences } from '../context/userPreferences';
import { formatLanguageToApi } from '../components/utils/api-utils';

export async function MoviesGenreGridService(genre: any, setState: any) {
	const { language } = useUserPreferences();

	const response = await axios({
		method: 'get',
		url: `https://api.themoviedb.org/3/discover/movie?with_genres=${genre}&api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`,
		headers: { Authorization: `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}` }
	});
	setState(response.data);
}

export async function TopMoviesGridService(setState: any) {
	const topMoviesUrl = 'https://api.themoviedb.org/3/movie/top_rated?api_key=8a9b6d3eb71a15a13f2cbef497bb7474&language=pt-BR';

	const topMoviesResponse = await axios({
		method: 'get',
		url: topMoviesUrl,
		headers: { Authorization: `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}` }
	});
	setState(topMoviesResponse.data);
}
